import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../services/api';

const ForgotPassword = () => {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [showError, setShowError] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');
  const [showSuccess, setShowSuccess] = useState(false);
  const [loading, setLoading] = useState(false);
  const [cooldown, setCooldown] = useState(0);

  useEffect(() => {
    let timer;
    if (cooldown > 0) {
      timer = setInterval(() => {
        setCooldown((prev) => prev - 1);
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [cooldown]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setShowError(false);
    setErrorMessage('');
    setShowSuccess(false);
    if (cooldown > 0) {
      setShowError(true);
      setErrorMessage(`Please wait ${cooldown} seconds before resending.`);
      return;
    }
    setLoading(true);
    try {
      const response = await api.post('/auth/forgot-password', { email: email.trim() });
      if (response.status === 200) {
        setShowSuccess(true);
        setCooldown(60);
      } else {
        setShowError(true);
        setErrorMessage('Failed to send reset link. Try again.');
      }
    } catch (err) {
      setShowError(true);
      setErrorMessage(err.response?.data || 'Failed to send reset link. Try again.');
      console.error('Forgot password error:', err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="g-auth-bg">
      <div className="g-auth-card">
        <div className="g-auth-logo">
          <span className="g-dot g-blue"></span>
          <span className="g-dot g-red"></span>
          <span className="g-dot g-yellow"></span>
          <span className="g-dot g-green"></span>
          <h2 className="g-brand">NeuroFleetX</h2>
        </div>
        <h1 className="g-title">Forgot Password</h1>
        <p className="g-subtitle">Enter your email to reset your password</p>
        {showError && <div className="g-error">{errorMessage}</div>}
        {showSuccess && (
          <div className="g-success">
            Reset link sent to <a href={`mailto:${email}`} className="text-blue-500 hover:underline">{email}</a>.
          </div>
        )}
        <form onSubmit={handleSubmit} className="g-form">
          <div className="g-field">
            <input
              type="email"
              className="g-input"
              placeholder="Email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              autoComplete="username"
              required
            />
          </div>
          <div className="g-actions">
            <button type="submit" className="g-btn" disabled={loading || cooldown > 0}>
              {loading ? 'Sending…' : cooldown > 0 ? `Wait ${cooldown}s` : 'Send Reset Link'}
            </button>
          </div>
        </form>
        <div className="g-help">
          <Link to="/login">Back to login</Link>
          <span> • </span>
          <Link to="/signup">Sign up</Link>
        </div>
      </div>
    </div>
  );
};

export default ForgotPassword;
